import{_ as t,o as a,c as o,a2 as i}from"./chunks/framework.Bix3-HpO.js";const u=JSON.parse('{"title":"Settings","description":"Nonaki Plugin Settings","frontmatter":{"title":"Settings","description":"Nonaki Plugin Settings","weight":70,"extra":{"order":70},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/nonaki/settings"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/nonaki/settings"}],["meta",{"property":"og:title","content":"Settings"}],["meta",{"property":"og:description","content":"Nonaki Plugin Settings"}],["meta",{"name":"twitter:title","content":"Settings"}],["meta",{"name":"twitter:description","content":"Nonaki Plugin Settings"}]]},"headers":[],"relativePath":"docs/nonaki/settings.md","filePath":"docs/nonaki/settings.md"}'),n={name:"docs/nonaki/settings.md"};function r(s,e,l,d,c,p){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h1><p>All plugin settings are in <strong>Nonaki</strong> → <strong>Settings</strong> in your WordPress dashboard.</p><hr><h2 id="redirect-slug" tabindex="-1">Redirect Slug <a class="header-anchor" href="#redirect-slug" aria-label="Permalink to &quot;Redirect Slug&quot;">​</a></h2><p>The redirect slug is the base path for all your links. The default is <code>links</code>, producing URLs like <code>yoursite.com/links/your-key</code>.</p><p>You can change it to anything you like — <code>go</code>, <code>visit</code>, <code>out</code>, or something custom. After saving, all existing redirects automatically use the new slug.</p><p>If you have set the slug via a code filter (<code>nonaki_slug</code>), the field will be locked and a notice will indicate that it is managed by code.</p><hr><h2 id="geoip" tabindex="-1">GeoIP <a class="header-anchor" href="#geoip" aria-label="Permalink to &quot;GeoIP&quot;">​</a></h2><p>Configure visitor country detection using the MaxMind GeoLite2 database.</p><ul><li><strong>MaxMind License Key</strong> — paste your key here and click <code>Save &amp; Update</code> to download the database files immediately. The field is write-only; for security the key is not displayed after saving.</li><li><strong>Auto-update databases weekly</strong> — enable to keep the GeoLite2 database current via a weekly background update.</li><li><strong>Database status</strong> — shows whether the <code>GeoLite2-City</code> and <code>GeoLite2-ASN</code> files are present and the date they were last updated.</li></ul><p>See <a href="/docs/nonaki/geoip">GeoIP</a> for full setup instructions.</p><hr><h2 id="import-export" tabindex="-1">Import / Export <a class="header-anchor" href="#import-export" aria-label="Permalink to &quot;Import / Export&quot;">​</a></h2><p>Upload a CSV or JSON file to import links in bulk, or download all your links for backup or migration. See <a href="/docs/nonaki/import-export">Import &amp; Export</a> for file format details and a downloadable template.</p><hr><h2 id="clear-analytics-data" tabindex="-1">Clear Analytics Data <a class="header-anchor" href="#clear-analytics-data" aria-label="Permalink to &quot;Clear Analytics Data&quot;">​</a></h2><p>The <code>Clear All Analytics</code> button permanently deletes all recorded clicks and impressions. Use this to start fresh or to fulfill a GDPR erasure request. This action cannot be undone.</p>',18)])])}const g=t(n,[["render",r]]);export{u as __pageData,g as default};
